 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    if (n === 1) {
        // Special case N=1. Person at pos=0 has 2 choices. k must be 0.
        // If k=0, result is 2. If k>0, result is 0.
        return k === 0 ? 2 : 0;
    }

    const MAX_VAL = n - 1;

    // --- Modular Arithmetic Helpers using BigInt ---

    // Modular exponentiation: (base^exp) % mod
    const power = (base, exp) => {
        let res = 1n;
        base %= MOD;
        while (exp > 0n) {
            if (exp % 2n === 1n) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2n;
        }
        return res;
    };

    // Modular inverse: n^(-1) % mod using Fermat's Little Theorem
    const modInverse = (n) => {
        return power(n, MOD - 2n);
