    // Precompute factorials
    const fact = new Array(MAX_VAL + 1);
    fact[0] = 1n;
    for (let i = 1; i <= MAX_VAL; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    // Combination function: nCk % MOD
    const nCr = (n, r) => {
        if (r < 0 || r > n) return 0n;
        if (r === 0 || r === n) return 1n;
        if (r > n / 2) r = n - r;

        // nCr = n! / (r! * (n-r)!)
        let numerator = fact[n];
        let denominator = (fact[r] * fact[n - r]) % MOD;

        return (numerator * modInverse(denominator)) % MOD;
    };

    // --- Main Logic ---

    // Total number of people who can be seen is N - 1.
    // We need to choose exactly K visible people from these N - 1 people.
    // This is C(N-1, K).

    const waysVisibility = nCr(n - 1, k);

